import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { DashboardStats } from '../types';
import api from '../utils/api';
import { useAuth } from '../hooks/useAuth';

export default function Dashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [loading, setLoading] = useState(true);
  const isStaff = user?.userType === 'user';

  useEffect(() => {
    api.get('/borrows/stats').then(r=>{setStats(r.data.data);setLoading(false);}).catch(()=>setLoading(false));
  }, []);

  if (loading) return (
    <div style={{display:'flex',alignItems:'center',justifyContent:'center',height:'100vh'}}>
      <div style={{width:36,height:36,border:'3px solid #c9a84c',borderTopColor:'transparent',borderRadius:'50%',animation:'spin 1s linear infinite'}}/>
      <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
    </div>
  );

  const cards = [
    { label:'Total Books',    value:stats?.totalBooks||0,    accent:'#6366f1', tag:'Library'  },
    { label:'Active Members', value:stats?.totalMembers||0,  accent:'#10b981', tag:'Enrolled' },
    { label:'Books Out',      value:stats?.activeBorrows||0, accent:'#c9a84c', tag:'Active'   },
    { label:'Overdue',        value:stats?.overdueBorrows||0,accent:'#ef4444', tag:'Urgent'   },
  ];

  return (
    <div className="page-enter" style={{padding:'40px 44px',maxWidth:1280,width:'100%'}}>
      <style>{`
        .scard{transition:all .22s !important;}
        .scard:hover{transform:translateY(-4px) !important;box-shadow:0 20px 50px rgba(0,0,0,0.4) !important;}
        .al:hover{filter:brightness(1.12);}
        .lrow:hover{background:rgba(255,255,255,0.04) !important;}
      `}</style>

      {/* ── Header ── */}
      <div style={{display:'flex',alignItems:'flex-start',justifyContent:'space-between',marginBottom:40}}>
        <div>
          <p style={{fontSize:12,color:'rgba(255,255,255,0.22)',letterSpacing:'2px',textTransform:'uppercase',marginBottom:10,fontWeight:600}}>
            {new Date().toLocaleDateString('en-US',{weekday:'long',year:'numeric',month:'long',day:'numeric'})}
          </p>
          <h1 style={{fontFamily:"'Playfair Display',serif",fontSize:40,fontWeight:700,color:'#fff',lineHeight:1.1,letterSpacing:'-1px'}}>
            Good day, {user?.name?.split(' ')[0]} 👋
          </h1>
        </div>
        <div style={{background:'rgba(201,168,76,0.08)',border:'1px solid rgba(201,168,76,0.18)',borderRadius:14,padding:'14px 22px',textAlign:'right',flexShrink:0}}>
          <div style={{fontSize:10,color:'rgba(255,255,255,0.25)',marginBottom:5,letterSpacing:'1.5px',textTransform:'uppercase',fontWeight:700}}>Logged in as</div>
          <div style={{fontSize:16,fontWeight:800,color:'#c9a84c',textTransform:'capitalize'}}>
            {user?.role==='librarian'?'Head Librarian':user?.role==='library_assistant'?'Library Assistant':user?.role}
          </div>
        </div>
      </div>

      {/* ── Alerts ── */}
      {isStaff && stats && stats.pendingMembers>0 && (
        <div className="al" onClick={()=>navigate('/members?status=pending')}
          style={{background:'rgba(245,158,11,0.07)',border:'1px solid rgba(245,158,11,0.18)',borderRadius:14,padding:'18px 24px',marginBottom:14,display:'flex',alignItems:'center',gap:18,cursor:'pointer',transition:'all .2s'}}>
          <div style={{width:44,height:44,background:'rgba(245,158,11,0.12)',borderRadius:12,display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0}}>
            <span style={{fontSize:20}}>⏳</span>
          </div>
          <div style={{flex:1}}>
            <div style={{fontSize:15,fontWeight:700,color:'#fbbf24',marginBottom:3}}>{stats.pendingMembers} account(s) waiting for approval</div>
            <div style={{fontSize:13,color:'rgba(251,191,36,0.45)'}}>Click to review pending members</div>
          </div>
          <span style={{fontSize:22,color:'rgba(251,191,36,0.35)'}}>→</span>
        </div>
      )}
      {isStaff && stats && stats.pendingRequests>0 && (
        <div className="al" onClick={()=>navigate('/requests')}
          style={{background:'rgba(99,102,241,0.07)',border:'1px solid rgba(99,102,241,0.18)',borderRadius:14,padding:'18px 24px',marginBottom:28,display:'flex',alignItems:'center',gap:18,cursor:'pointer',transition:'all .2s'}}>
          <div style={{width:44,height:44,background:'rgba(99,102,241,0.12)',borderRadius:12,display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0}}>
            <span style={{fontSize:20}}>🔔</span>
          </div>
          <div style={{flex:1}}>
            <div style={{fontSize:15,fontWeight:700,color:'#a5b4fc',marginBottom:3}}>{stats.pendingRequests} borrow request(s) pending</div>
            <div style={{fontSize:13,color:'rgba(165,180,252,0.45)'}}>Click to review and approve</div>
          </div>
          <span style={{fontSize:22,color:'rgba(165,180,252,0.35)'}}>→</span>
        </div>
      )}

      {stats && (
        <>
          {/* ── Stat Cards ── */}
          <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:20,marginBottom:28}}>
            {cards.map(c=>(
              <div key={c.label} className="scard"
                style={{background:'#11112a',border:`1px solid rgba(255,255,255,0.07)`,borderRadius:20,padding:'28px 26px 22px',position:'relative',overflow:'hidden',cursor:'default'}}>
                {/* ambient glow */}
                <div style={{position:'absolute',top:0,right:0,width:120,height:120,background:c.accent+'14',borderRadius:'50%',filter:'blur(40px)',pointerEvents:'none',transform:'translate(30%,-30%)'}}/>
                {/* tag */}
                <div style={{display:'flex',justifyContent:'flex-end',marginBottom:22}}>
                  <span style={{fontSize:11,fontWeight:700,padding:'4px 13px',borderRadius:99,background:c.accent+'18',color:c.accent,letterSpacing:'.5px',border:`1px solid ${c.accent}28`}}>{c.tag}</span>
                </div>
                {/* number */}
                <div style={{fontFamily:"'Playfair Display',serif",fontSize:52,fontWeight:700,color:'#fff',lineHeight:1,marginBottom:8,letterSpacing:'-2px'}}>{c.value}</div>
                {/* label */}
                <div style={{fontSize:14,color:'rgba(255,255,255,0.35)',fontWeight:500,marginBottom:18,letterSpacing:'.3px'}}>{c.label}</div>
                {/* bar */}
                <div style={{height:3,background:'rgba(255,255,255,0.05)',borderRadius:99,overflow:'hidden'}}>
                  <div style={{height:'100%',width:c.value>0?'65%':'6%',background:`linear-gradient(90deg,${c.accent},${c.accent}55)`,borderRadius:99,transition:'width 1.2s ease'}}/>
                </div>
              </div>
            ))}
          </div>

          {/* ── Bottom ── */}
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:22}}>

            {/* Recent Borrows */}
            <div style={{background:'#11112a',border:'1px solid rgba(255,255,255,0.07)',borderRadius:20,padding:28}}>
              <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:24}}>
                <h3 style={{fontFamily:"'Playfair Display',serif",fontSize:20,fontWeight:700,color:'#fff',letterSpacing:'-.3px'}}>Recent Borrows</h3>
                <span style={{fontSize:11,color:'rgba(255,255,255,0.22)',background:'rgba(255,255,255,0.04)',border:'1px solid rgba(255,255,255,0.07)',padding:'5px 13px',borderRadius:99,fontWeight:600}}>Latest 5</span>
              </div>
              {stats.recentBorrows.length ? stats.recentBorrows.map((b:any)=>(
                <div key={b.id} className="lrow" style={{display:'flex',alignItems:'center',gap:14,padding:'12px 14px',borderRadius:12,marginBottom:6,border:'1px solid transparent',transition:'background .15s'}}>
                  <div style={{width:8,height:8,borderRadius:'50%',background:b.status==='returned'?'#34d399':b.status==='overdue'?'#f87171':'#fbbf24',flexShrink:0,boxShadow:`0 0 8px ${b.status==='returned'?'#34d399':b.status==='overdue'?'#f87171':'#fbbf24'}88`}}/>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:14,fontWeight:600,color:'#fff',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{b.title}</div>
                    <div style={{fontSize:12,color:'rgba(255,255,255,0.28)',marginTop:3}}>{b.member_name} · <span style={{textTransform:'capitalize'}}>{b.account_type}</span></div>
                  </div>
                  <span style={{fontSize:11,fontWeight:700,padding:'4px 11px',borderRadius:99,flexShrink:0,textTransform:'capitalize',
                    background:b.status==='returned'?'rgba(52,211,153,0.1)':b.status==='overdue'?'rgba(248,113,113,0.1)':'rgba(251,191,36,0.1)',
                    color:b.status==='returned'?'#34d399':b.status==='overdue'?'#f87171':'#fbbf24'
                  }}>{b.status}</span>
                </div>
              )) : (
                <div style={{textAlign:'center',padding:'40px 0'}}>
                  <div style={{fontSize:13,color:'rgba(255,255,255,0.18)',fontStyle:'italic'}}>No borrows yet</div>
                </div>
              )}
            </div>

            {/* Popular Books */}
            <div style={{background:'#11112a',border:'1px solid rgba(255,255,255,0.07)',borderRadius:20,padding:28}}>
              <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:24}}>
                <h3 style={{fontFamily:"'Playfair Display',serif",fontSize:20,fontWeight:700,color:'#fff',letterSpacing:'-.3px'}}>Popular Books</h3>
                <span style={{fontSize:11,color:'rgba(255,255,255,0.22)',background:'rgba(255,255,255,0.04)',border:'1px solid rgba(255,255,255,0.07)',padding:'5px 13px',borderRadius:99,fontWeight:600}}>Top 5</span>
              </div>
              {stats.popularBooks.length ? stats.popularBooks.map((b:any,i:number)=>(
                <div key={b.title} className="lrow" style={{display:'flex',alignItems:'center',gap:14,padding:'12px 14px',borderRadius:12,marginBottom:6,border:'1px solid transparent',transition:'background .15s'}}>
                  <div style={{width:28,height:28,borderRadius:8,flexShrink:0,display:'flex',alignItems:'center',justifyContent:'center',fontSize:13,fontWeight:800,
                    background:i===0?'linear-gradient(135deg,#c9a84c,#a87d30)':i===1?'rgba(156,163,175,0.12)':i===2?'rgba(180,100,60,0.12)':'rgba(255,255,255,0.04)',
                    color:i===0?'#1a1a2e':i===1?'#9ca3af':i===2?'#c07840':'rgba(255,255,255,0.25)',
                    boxShadow:i===0?'0 4px 14px rgba(201,168,76,0.5)':'none'
                  }}>{i+1}</div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:14,fontWeight:600,color:'#fff',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{b.title}</div>
                    <div style={{fontSize:12,color:'rgba(255,255,255,0.28)',marginTop:3}}>{b.author}</div>
                  </div>
                  <div style={{fontSize:15,fontWeight:800,color:'#c9a84c',flexShrink:0}}>{b.borrow_count}×</div>
                </div>
              )) : (
                <div style={{textAlign:'center',padding:'40px 0'}}>
                  <div style={{fontSize:13,color:'rgba(255,255,255,0.18)',fontStyle:'italic'}}>No data yet</div>
                </div>
              )}
            </div>
          </div>
        </>
      )}
    </div>
  );
}
